solutions.python:
import sys
from typing import List

class Solution:
    def solve(self, nums: List[int]) -> int:
        ans = 0
        for num in nums:
            ans ^= abs(num)
        return ans

if __name__ == '__main__':
    n = int(sys.stdin.readline())
    nums = list(map(int, sys.stdin.readline().split()))
    print(Solution().solve(nums))

